class _MiniDotAnimator extends StatefulWidget {
  final Color color;
  const _MiniDotAnimator({Key? key, required this.color}) : super(key: key);

  @override
  __MiniDotAnimatorState createState() => __MiniDotAnimatorState();
}

class __MiniDotAnimatorState extends State<_MiniDotAnimator> with SingleTickerProviderStateMixin {
  late AnimationController _controller;

  @override
  void initState() {
    super.initState();
    _controller = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 1000),
    )..repeat();
  }

  @override
  void dispose() {
    _controller.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return AnimatedBuilder(
      animation: _controller,
      builder: (context, child) {
        String dots = ".";
        if (_controller.value > 0.33) dots = "..";
        if (_controller.value > 0.66) dots = "...";
        return Text(
          dots,
          style: TextStyle(
            color: widget.color,
            fontWeight: FontWeight.bold,
            fontSize: 14,
          ),
        );
      },
    );
  }
}
